import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Card, Input, Textarea, InputNumber, Segmented, Button, Upload, Collapsible, Chip, Separator, icon } from 'decantr/components';

code.example:
function CreationForm() {
  const { div, h3, label } = tags;
  const [title, setTitle] = createSignal('');
  const [items, setItems] = createSignal(['']);

  const addItem = () => setItems([...items(), '']);

  return div({ class: css('_flex _col _gap6 _mw[720px] _mxAuto _p4') },
    Upload({ accept: 'image/*', variant: 'dragger' }, 'Upload cover photo'),
    Card({},
      Card.Header({}, h3({ class: css('_heading5') }, 'Basic Info')),
      Card.Body({ class: css('_flex _col _gap3') },
        Input({ label: 'Title', placeholder: 'Name', value: title, onchange: e => setTitle(e.target.value) }),
        Textarea({ label: 'Description', placeholder: 'Brief description...', rows: 3 })
      )
    ),
    Card({},
      Card.Header({}, h3({ class: css('_heading5') }, 'Details')),
      Card.Body({ class: css('_flex _col _gap3') },
        div({ class: css('_grid _gc3 _gap3') },
          InputNumber({ label: 'Prep (min)', min: 0 }),
          InputNumber({ label: 'Cook (min)', min: 0 }),
          InputNumber({ label: 'Servings', min: 1 })
        ),
        Segmented({ label: 'Difficulty', options: ['Easy', 'Medium', 'Hard'] })
      )
    ),
    Card({},
      Card.Header({}, h3({ class: css('_heading5') }, 'Items')),
      Card.Body({ class: css('_flex _col _gap2') },
        ...items().map((_, i) =>
          Input({ placeholder: `Item ${i + 1}` })
        ),
        Button({ variant: 'outline', size: 'sm', onclick: addItem }, icon('plus'), 'Add Item')
      )
    ),
    div({ class: css('_flex _jce _gap3') },
      Button({ variant: 'outline' }, 'Save Draft'),
      Button({ variant: 'primary' }, 'Publish')
    )
  );
}

