import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Card, Input, Textarea, InputNumber, Select, Segmented, Button, Upload, Tabs, Separator, Badge, icon } from 'decantr/components';

code.example:
function StructuredForm() {
  const { div, h3, span } = tags;
  const [items, setItems] = createSignal([{ qty: '', unit: '', name: '', prep: '' }]);
  const [sections, setSections] = createSignal([{ title: 'Main', steps: [{ text: '', time: 0 }] }]);
  const units = ['g', 'kg', 'ml', 'l', 'cup', 'tbsp', 'tsp', 'oz', 'lb', 'piece'];

  return div({ class: css('_flex _col _gap6 _mw[840px] _mxAuto _p4') },
    Upload({ accept: 'image/*', variant: 'dragger' }, 'Upload cover photo'),
    Card({},
      Card.Header({}, h3({ class: css('_heading5') }, 'Basic Info')),
      Card.Body({ class: css('_flex _col _gap3') },
        Input({ label: 'Title', placeholder: 'Name' }),
        Textarea({ label: 'Description', rows: 3 }),
        Segmented({ label: 'Scale', options: ['1x', '2x', '4x'] })
      )
    ),
    Card({},
      Card.Header({}, h3({ class: css('_heading5') }, 'Structured Items')),
      Card.Body({ class: css('_flex _col _gap2') },
        ...items().map((item, i) =>
          div({ class: css('_grid _gc4 _gap2 _aic') },
            InputNumber({ placeholder: 'Qty', size: 'sm' }),
            Select({ placeholder: 'Unit', options: units, size: 'sm' }),
            Input({ placeholder: 'Name', size: 'sm' }),
            Input({ placeholder: 'Notes', size: 'sm' })
          )
        ),
        Button({ variant: 'outline', size: 'sm' }, icon('plus'), 'Add Item')
      )
    ),
    Card({},
      Card.Header({}, h3({ class: css('_heading5') }, 'Sections')),
      Card.Body({ class: css('_flex _col _gap4') },
        ...sections().map((sec, si) =>
          div({ class: css('_flex _col _gap3 _p3 _bgmuted _r4') },
            Input({ value: sec.title, placeholder: 'Section name', size: 'sm' }),
            ...sec.steps.map((step, i) =>
              div({ class: css('_flex _gap2 _aic') },
                Badge({ variant: 'outline' }, `${si + 1}.${i + 1}`),
                Textarea({ placeholder: 'Step description', rows: 2, class: css('_flex1') }),
                InputNumber({ placeholder: 'Min', size: 'sm', class: css('_w[80px]') })
              )
            ),
            Button({ variant: 'outline', size: 'sm' }, icon('plus'), 'Add Step')
          )
        ),
        Button({ variant: 'outline', size: 'sm' }, icon('plus'), 'Add Section')
      )
    ),
    div({ class: css('_flex _jce _gap3') },
      Button({ variant: 'outline' }, 'Save Draft'),
      Button({ variant: 'primary' }, 'Publish')
    )
  );
}

